async def validate_bearer_token(
    credentials: Optional[HTTPAuthorizationCredentials] = Security(security),
    validator: SecureTokenValidator = Depends(get_token_validator)
) -> str:
    """
    Dependency for validating OAuth 2.0 bearer tokens.
    Implements secure token validation with proper error handling.
    """
    # Check if Authorization header is present
    if not credentials:
        logger.warning("Missing Authorization header")
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Missing authentication credentials",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    # Verify scheme is Bearer
    if credentials.scheme.lower() != "bearer":
        logger.warning(f"Invalid authentication scheme: {credentials.scheme}")
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid authentication scheme",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    token = credentials.credentials
    
    # Validate token format (basic sanity check)
    if not token or not isinstance(token, str):
        logger.warning("Invalid token format")
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid token format",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    # Prevent excessively long tokens (DoS protection)
    if len(token) > 1024:
        logger.warning("Token exceeds maximum length")
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid token",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    # Validate token against Redis cache
    is_valid = await validator.validate_token(token)
    
    if not is_valid:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid or expired token",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    # Return hashed token for internal use (never return plaintext)
    return validator._hash_token(token)


